import React from 'react';
import { Grid, Paper, Button, Typography, TextField } from '@mui/material';
import { makeStyles } from '@mui/styles';
import { useNavigate } from 'react-router-dom';
import signpng from './signupfinal.png';

const useStyles = makeStyles((theme) => ({
  image: {
    width: 'auto',
    height: '600px',
  },
}));

export const Signup = () => {
  const navigate = useNavigate();
  const classes = useStyles();

  return (
    <Grid
      container
      justifyContent="center"
      alignItems="center"
      style={{ minHeight: '100vh' }}
    >
      <Paper sx={{  width: '1200px', height: '600px' }} elevation={10}>

        <Grid container>
          
          <Grid item xs={6}>
            <img src={signpng} alt="The signup" className={classes.image} />
          </Grid>

          
          <Grid item xs={6} container direction="column" justifyContent="center" alignItems="center">

            <Typography variant="h2">Hello world how are you</Typography>
            
            <TextField label="Name" variant="outlined" fullWidth margin="normal" />
            <TextField label="Password" type="password" variant="outlined" fullWidth margin="normal" />
            <Button variant="contained" onClick={() => { navigate('/signup') }}>Signup</Button>

          </Grid>
        </Grid>
      </Paper>
    </Grid>
  );
};
